#!/usr/bin/env python3\n\"\"\"\nEnvía informes matutinos a Discord vía webhook/API del bot.\nUso: python3 send-informe-to-discord.py \"titulo\" \"contenido\" \"tipo\"\n      o por stdin: echo \"contenido\" | python3 send-informe-to-discord.py\n\"\"\"\n\nimport os\nimport sys\nimport json\nimport requests\nfrom datetime import datetime\nimport re\n\n# Credenciales\nBOT_TOKEN = os.getenv('DISCORD_BOT_TOKEN')\nCHANNEL_ID = os.getenv('DISCORD_CHANNEL_ID')\n\nif not BOT_TOKEN or not CHANNEL_ID:\n    print(\"❌ Error: DISCORD_BOT_TOKEN o DISCORD_CHANNEL_ID no configurados\")\n    sys.exit(1)\n\nAPI_URL = f\"https://discord.com/api/v10/channels/{CHANNEL_ID}/messages\"\nHEADERS = {\n    \"Authorization\": f\"Bot {BOT_TOKEN}\",\n    \"Content-Type\": \"application/json\"\n}\n\ndef split_text(text, max_length=2000):\n    \"\"\"Divide el texto en chunks para Discord (máx 2000 caracteres).\"\"\"\n    if len(text) <= max_length:\n        return [text]\n    \n    chunks = []\n    current_chunk = \"\"\n    lines = text.split(\"\\n\")\n    \n    for line in lines:\n        if len(current_chunk) + len(line) + 1 > max_length:\n            if current_chunk:\n                chunks.append(current_chunk)\n            current_chunk = line + \"\\n\"\n        else:\n            current_chunk += line + \"\\n\"\n    \n    if current_chunk:\n        chunks.append(current_chunk)\n    \n    return chunks\n\ndef get_color_for_section(section_name):\n    \"\"\"Retorna color Discord para cada sección.\"\"\"\n    colors = {\n        \"sistema\": 0x3498DB,      # Azul\n        \"seguridad\": 0xE74C3C,    # Rojo\n        \"salud\": 0x2ECC71,        # Verde\n        \"tareas\": 0xF39C12,       # Naranja\n        \"auditoria\": 0x9B59B6,    # Púrpura\n        \"ideas\": 0x1ABC9C,        # Turquesa\n        \"consumo\": 0x34495E,      # Gris oscuro\n        \"garmin\": 0x27AE60        # Verde oscuro\n    }\n    \n    for keyword, color in colors.items():\n        if keyword.lower() in section_name.lower():\n            return color\n    return 0x95A5A6  # Gris por defecto\n\ndef parse_sections(contenido):\n    \"\"\"Parsea el contenido para extraer secciones.\"\"\"\n    # Busca patrones como \"**SECCIÓN X: ...**\"\n    sections = re.split(r'^\\*\\*(?:SECCIÓN|##)\\s+([^:]+):\\s*(.+?)\\*\\*', contenido, flags=re.MULTILINE)\n    \n    result = []\n    for i in range(1, len(sections), 2):\n        if i + 1 < len(sections):\n            result.append({\n                \"title\": sections[i].strip(),\n                \"content\": sections[i + 1].strip()\n            })\n    \n    return result if result else [{\"title\": \"Informe\", \"content\": contenido}]\n\ndef send_to_discord(titulo, contenido, tipo=\"informe\"):\n    \"\"\"Envía el informe a Discord usando embeds.\"\"\"\n    \n    print(f\"📤 Enviando '{titulo}' a Discord...\")\n    \n    # Parsear secciones\n    sections = parse_sections(contenido)\n    \n    if not sections:\n        print(\"❌ No hay contenido para enviar\")\n        return False\n    \n    # Crear embeds bonitos\n    embeds = []\n    \n    # Embed principal con metadata\n    main_embed = {\n        \"title\": f\"📊 {titulo}\",\n        \"description\": f\"Generado: {datetime.now().strftime('%d/%m/%Y %H:%M')}\",\n        \"color\": 0x3498DB if tipo == \"matutino\" else 0x9B59B6,\n        \"footer\": {\"text\": \"OpenClaw Automation\"}\n    }\n    embeds.append(main_embed)\n    \n    # Embeds para cada sección\n    for section in sections[:10]:  # Discord permite máx 10 embeds\n        section_title = section[\"title\"][:256]  # Límite Discord\n        section_content = section[\"content\"][:4096]  # Límite Discord\n        \n        embed = {\n            \"title\": section_title,\n            \"description\": section_content,\n            \"color\": get_color_for_section(section_title),\n            \"inline\": False\n        }\n        embeds.append(embed)\n    \n    # Enviar a Discord\n    payload = {\"embeds\": embeds}\n    \n    try:\n        response = requests.post(API_URL, json=payload, headers=HEADERS, timeout=10)\n        response.raise_for_status()\n        print(f\"✅ Informe enviado a Discord ({len(embeds)} embeds)\")\n        return True\n    except requests.exceptions.RequestException as e:\n        print(f\"❌ Error enviando a Discord: {e}\")\n        return False\n\ndef send_simple_message(contenido):\n    \"\"\"Envía un mensaje simple dividido en chunks si es necesario.\"\"\"\n    print(f\"📤 Enviando informe a Discord...\")\n    \n    chunks = split_text(contenido, max_length=2000)\n    \n    success_count = 0\n    for i, chunk in enumerate(chunks):\n        # Markdown para Discord: ``` para código, ** para bold, etc.\n        payload = {\n            \"content\": f\"📊 **Informe Matutino** ({i+1}/{len(chunks)})\\n\\n{chunk}\"\n        }\n        \n        try:\n            response = requests.post(API_URL, json=payload, headers=HEADERS, timeout=10)\n            response.raise_for_status()\n            success_count += 1\n        except requests.exceptions.RequestException as e:\n            print(f\"❌ Error en chunk {i+1}: {e}\")\n    \n    if success_count == len(chunks):\n        print(f\"✅ Informe enviado ({len(chunks)} mensajes)\")\n        return True\n    else:\n        print(f\"⚠️ Enviados {success_count}/{len(chunks)} mensajes\")\n        return success_count > 0\n\nif __name__ == \"__main__\":\n    if len(sys.argv) > 3:\n        # Uso: send-informe-to-discord.py \"Título\" \"Contenido\" \"tipo\"\n        titulo = sys.argv[1]\n        contenido = sys.argv[2]\n        tipo = sys.argv[3] if len(sys.argv) > 3 else \"informe\"\n        send_to_discord(titulo, contenido, tipo)\n    elif len(sys.argv) > 2:\n        # Uso: send-informe-to-discord.py \"Título\" \"Contenido\"\n        titulo = sys.argv[1]\n        contenido = sys.argv[2]\n        send_to_discord(titulo, contenido)\n    elif len(sys.argv) > 1:\n        # Leer contenido del primer argumento (puede ser archivo o texto)\n        arg = sys.argv[1]\n        if os.path.isfile(arg):\n            with open(arg, 'r') as f:\n                contenido = f.read()\n            titulo = os.path.basename(arg)\n        else:\n            contenido = arg\n            titulo = \"Informe\"\n        send_simple_message(contenido)\n    else:\n        # Leer de stdin\n        contenido = sys.stdin.read()\n        if contenido.strip():\n            send_simple_message(contenido)\n        else:\n            print(\"❌ No hay contenido para enviar\")\n            sys.exit(1)\n"}}]